<span class="line"><span style="--shiki-light:#A626A4;--shiki-dark:#C678DD;">    error_log </span><span style="--shiki-light:#383A42;--shiki-dark:#ABB2BF;">/var/log/nginx/demo.error.log </span><span style="--shiki-light:#986801;--shiki-dark:#D19A66;">warn</span><span style="--shiki-light:#383A42;--shiki-dark:#ABB2BF;">;</span></span>
